export function updateHUD(): void {
  const lf = document.getElementById('life-fill');
  const cc = document.getElementById('cards-count');
  const bn = document.getElementById('biome-name');
  if (!lf || !cc || !bn) return; // DOM not ready yet

  const state = store.getState();
  const lifePercent = (state.run.life / LIFE_MAX) * 100;
  lf.style.width = `${lifePercent}%`;
  if (lifePercent <= 25) {
    lf.style.background = 'linear-gradient(90deg,#8b0000,#cd5c5c)';
  } else if (lifePercent <= 50) {
    lf.style.background = 'linear-gradient(90deg,#8b4513,#cd853f)';
  } else {
    lf.style.background = 'linear-gradient(90deg,#2e6b2e,#5a9a5a)';
  }
  cc.textContent = `Carte ${state.run.cardsPlayed}`;
  const biome = BIOMES[state.run.biome];
  bn.textContent = biome?.name ?? state.run.biome;
  // ... rest unchanged
}

